#include <stdio.h>
#include <math.h>

typedef long long int ll;

int TorF(int* v, int n, long double val, ll h) {
    ll time = 0;
    for (int i = 0; i < n; i++) {
        time += (ll)ceil(v[i] / val);
    }
    return time <= h;
}

int main() {
    int t;
    scanf("%d", &t);
    while (t--) {
        ll n, h;
        scanf("%lld %lld", &n, &h);
        int v[n];
        for (int i = 0; i < n; i++) {
            scanf("%d", &v[i]);
        }

        ll first = 1, last = 1e9;

        while (first < last) {
            ll mid = first + (last - first) / 2;

            if (TorF(v, n, (long double)mid, h)) {
                last = mid;
            } else {
                first = mid + 1;
            }
        }
        printf("%lld\n", first);
    }
    return 0;
}

